PyTypeObject* DoInitWrapperVector2D(const UScriptStruct* InStruct, PyTypeObject* InSuperType)
{
	if (InStruct == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedStructType(InStruct))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedStructType(InStruct));
	}

	PyTypeObject* PyType = &UPyWrapperVector2DType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperStructType;
	PyType->tp_init = (initproc)&FFuncs_Vector2D::Init;
	PyType->tp_methods = FUPyWrapperVector2DPyMethodDefs;
	PyType->tp_getset = FUPyWrapperVector2DGetSets;
	PyType->tp_richcompare = (richcmpfunc)&FFuncs_Vector2D::RichCmp;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNumberFuncs_Vector2D::Op_add;
	PyNumber.nb_inplace_add = (binaryfunc)&FNumberFuncs_Vector2D::Op_iadd;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNumberFuncs_Vector2D::Op_imul;
	PyNumber.nb_inplace_subtract = (binaryfunc)&FNumberFuncs_Vector2D::Op_isub;
	PyNumber.nb_multiply = (binaryfunc)&FNumberFuncs_Vector2D::Op_mul;
	PyNumber.nb_negative = (unaryfunc)&FNumberFuncs_Vector2D::Op_neg;
	PyNumber.nb_or = (binaryfunc)&FNumberFuncs_Vector2D::Op_or;
	PyNumber.nb_subtract = (binaryfunc)&FNumberFuncs_Vector2D::Op_sub;
	PyNumber.nb_true_divide = (binaryfunc)&FNumberFuncs_Vector2D::Op_truediv;
	PyNumber.nb_xor = (binaryfunc)&FNumberFuncs_Vector2D::Op_xor;
	PyType->tp_as_number = &PyNumber;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyConstantDef::AddConstantsToType(FConstants_Vector2D::Table(), PyType);
		FUPyWrapperTypeRegistry::Get().RegisterWrappedStructType(InStruct, PyType);
		return PyType;
	}

	return nullptr;

}

void InitializeUPyWrapperVector2D(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterInlineStructFactory(StaticCastSharedRef<const IUPyWrapperInlineStructFactory>(MakeShared<TUPyWrapperInlineStructFactory<FVector2D>>()));
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedStructCreateFunc(TBaseStructure<FVector2D>::Get(), DoInitWrapperVector2D);
}

PyObject* FUPyWrapperVector2D::CreateInstance(const FVector2D& InValue, const FUPyWrapperOwnerContext& InOwnerContext, const EUPyConversionMethod InConversionMethod)
{
	return (PyObject*)FUPyWrapperStructFactory::Get().CreateInstance(&UPyWrapperVector2DType, TBaseStructure<FVector2D>::Get(), (void*)&InValue, InOwnerContext, InConversionMethod);
}

FUPyWrapperVector2D* UPyIsVector2D(PyObject* InSelf)
{
	if (InSelf && PyObject_TypeCheck(InSelf, &UPyWrapperVector2DType))
	{
		return (FUPyWrapperVector2D*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult NativizeStructInstance(PyObject* PyObj, FVector2D& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperVector2D* PyVector = UPyIsVector2D(PyObj))
		{
			OutVal = *PyVector->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("NativizeStructInstance"), *FString::Printf(TEXT("Cannot nativize '%s' as 'FVector2D'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
	
	FUPyConversionResult PythonizeStructInstance(const FVector2D& InVal, PyObject*& OutPyObj, const ESetErrorState SetErrorState)
	{
		OutPyObj = FUPyWrapperVector2D::CreateInstance(InVal, FUPyWrapperOwnerContext(), EUPyConversionMethod::Copy);
		return FUPyConversionResult::Success();
	}
}
